static rudo_glyph_info empty_glyph_info(void) { rudo_glyph_info v; memset(&v, 0, sizeof(v)); return v; }
static char *dup_string(const char *s) { return s ? rudo_strdup(s) : NULL; }
static char *dup_string_n(const char *s, size_t n) { return rudo_strndup(s, n); }
static char *trimmed_copy(const char *s) { char *copy; char *t; if (!s || !*s) return rudo_strdup(RUDO_DEFAULT_FONT_FAMILY); copy = rudo_strdup(s); if (!copy) return NULL; t = rudo_trim(copy); if (t != copy) memmove(copy, t, strlen(t) + 1u); if (!*copy) { free(copy); return rudo_strdup(RUDO_DEFAULT_FONT_FAMILY); } return copy; }
static int path_exists(const char *path) { return path && access(path, R_OK) == 0; }
static char *path_join2(const char *a, const char *b) { return rudo_path_join2(a, b); }
static char *path_join3(const char *a, const char *b, const char *c) { return rudo_path_join3(a, b, c); }
static int mkdir_p(const char *path) { char tmp[PATH_MAX]; size_t i, n; if (!path) return 0; n = strlen(path); if (!n || n >= sizeof(tmp)) return 0; memcpy(tmp, path, n + 1u); for (i = 1; i < n; ++i) if (tmp[i] == '/') { tmp[i] = 0; if (tmp[0] && mkdir(tmp, 0700) && errno != EEXIST) return 0; tmp[i] = '/'; } return mkdir(tmp, 0700) == 0 || errno == EEXIST; }
static char *cache_base_dir(void) { const char *xdg = getenv("XDG_CACHE_HOME"); const char *home; if (xdg && *xdg) return dup_string(xdg); home = getenv("HOME"); return (home && *home) ? path_join2(home, ".cache") : NULL; }
static char *sanitize_cache_key(const char *request) { const char *src = request ? request : RUDO_DEFAULT_FONT_FAMILY; size_t n = strlen(src), i, out_len = 0; int last_sep = 0; char *out = (char *)malloc((n ? n : 1u) + 1u); if (!out) return NULL; for (i = 0; i < n && out_len < 80u; ++i) { unsigned char ch = (unsigned char)src[i]; if (isalnum(ch)) { out[out_len++] = (char)tolower(ch); last_sep = 0; } else if (!last_sep) { out[out_len++] = '_'; last_sep = 1; } } while (out_len && out[out_len - 1u] == '_') --out_len; if (!out_len) { memcpy(out, "default", 8u); return out; } out[out_len] = 0; return out; }
static char *font_plan_cache_path(const char *request) { char *base = cache_base_dir(), *app_dir, *cache_dir, *key, *file_name, *path; size_t key_len; if (!base) return NULL; app_dir = path_join2(base, RUDO_APP_NAME); free(base); if (!app_dir) return NULL; cache_dir = path_join2(app_dir, FONT_PLAN_CACHE_DIR); free(app_dir); if (!cache_dir) return NULL; key = sanitize_cache_key(request); if (!key) { free(cache_dir); return NULL; } key_len = strlen(key); file_name = (char *)malloc(key_len + 5u); if (!file_name) { free(key); free(cache_dir); return NULL; } memcpy(file_name, key, key_len); memcpy(file_name + key_len, ".txt", 5u); free(key); path = path_join2(cache_dir, file_name); free(file_name); free(cache_dir); return path; }
static char *read_cached_regular_path(const char *request) { char *path = font_plan_cache_path(request), *line = NULL, *regular = NULL; size_t cap = 0; ssize_t nread; FILE *fp; if (!path) return NULL; fp = fopen(path, "r"); free(path); if (!fp) return NULL; while ((nread = getline(&line, &cap, fp)) >= 0) { char *eq, *value, *end; if (!nread) continue; eq = strchr(line, '='); if (!eq) continue; *eq = 0; if (strcmp(line, "regular")) continue; value = eq + 1; end = value + strlen(value); while (end > value && (end[-1] == '\n' || end[-1] == '\r' || isspace((unsigned char)end[-1]))) --end; while (*value && isspace((unsigned char)*value)) ++value; if (end > value) regular = dup_string_n(value, (size_t)(end - value)); break; } free(line); fclose(fp); if (!path_exists(regular)) { free(regular); return NULL; } return regular; }
