static int grow_array(void **ptr, size_t elem_size, size_t *cap, size_t need) { size_t new_cap; void *new_ptr; if (need <= *cap) return 1; new_cap = *cap ? *cap : 8u; while (new_cap < need) new_cap *= 2u; new_ptr = realloc(*ptr, elem_size * new_cap); if (!new_ptr) return 0; *ptr = new_ptr; *cap = new_cap; return 1; }
