static int append_unique_string(char ***items, size_t *len, size_t *cap, const char *value) { char *copy; if (!value || !*value || string_array_contains(*items, *len, value)) return 1; if (!grow_array((void **)items, sizeof(char *), cap, *len + 1u)) return 0; copy = dup_string(value); if (!copy) return 0; (*items)[(*len)++] = copy; return 1; }
static void free_string_array(char **items, size_t len) { size_t i; if (!items) return; for (i = 0; i < len; ++i) free(items[i]); free(items); }

