static int has_font_extension(const char *name) { const char *dot = name ? strrchr(name, '.') : NULL; return dot && (!strcasecmp(dot, ".ttf") || !strcasecmp(dot, ".otf")); }
static char *find_first_font_in_dir(const char *dir_path) { DIR *dir = opendir(dir_path); struct dirent *entry; char **subdirs = NULL; size_t subdir_len = 0, subdir_cap = 0; char *found = NULL; if (!dir) return NULL; while ((entry = readdir(dir))) { char *path; struct stat st; if (!strcmp(entry->d_name, ".") || !strcmp(entry->d_name, "..")) continue; path = path_join2(dir_path, entry->d_name); if (!path) continue; if (stat(path, &st)) { free(path); continue; } if (S_ISREG(st.st_mode) && has_font_extension(entry->d_name)) { found = path; break; } if (S_ISDIR(st.st_mode)) { if (!grow_array((void **)&subdirs, sizeof(char *), &subdir_cap, subdir_len + 1u)) { free(path); continue; } subdirs[subdir_len++] = path; } else free(path); } closedir(dir); if (found) { free_string_array(subdirs, subdir_len); return found; } while (subdir_len) { char *sub = subdirs[--subdir_len]; found = find_first_font_in_dir(sub); free(sub); if (found) { free_string_array(subdirs, subdir_len); return found; } } free(subdirs); return NULL; }
static char *scan_filesystem_for_any_font(void) { static const char *const dirs[] = { "/usr/share/fonts", "/usr/local/share/fonts", "/nix/var/nix/profiles/system/sw/share/X11/fonts", "/run/current-system/sw/share/X11/fonts" }; const char *home; size_t i; char *path = NULL; for (i = 0; i < RUDO_ARRAY_LEN(dirs); ++i) { path = find_first_font_in_dir(dirs[i]); if (path) return path; } home = getenv("HOME"); if (home && *home) { char *dir = path_join3(home, ".local", "share/fonts"); if (dir) { path = find_first_font_in_dir(dir); free(dir); if (path) return path; } dir = path_join2(home, ".fonts"); if (dir) { path = find_first_font_in_dir(dir); free(dir); if (path) return path; } } return NULL; }
static char *resolve_regular_font_path(const char *request) { char *path = read_cached_regular_path(request); if (path) return path; path = fontconfig_match_file(request); if (!path && strcmp(request, RUDO_DEFAULT_FONT_FAMILY)) path = fontconfig_match_file(RUDO_DEFAULT_FONT_FAMILY); if (!path) path = scan_filesystem_for_any_font(); if (path) write_cached_regular_path(request, path); return path; }
