static void ft_font_init(FtFont *font) { font->face = NULL; font->path = NULL; }
static void ft_font_drop(FtFont *font) { if (!font) return; if (font->face && ensure_ft()) g_ft.Done_Face((FT_Face)font->face); font->face = NULL; free(font->path); font->path = NULL; }
static void ft_face_set_size(FT_Face face, float size_px) { FT_F26Dot6 size_26_6; if (!face) return; if (size_px < 1.0f) size_px = 1.0f; size_26_6 = (FT_F26Dot6)(size_px * FREETYPE_FIXED_POINT_SCALE + 0.5f); if (g_ft.Set_Char_Size(face, 0, size_26_6, 72u, 72u)) g_ft.Set_Pixel_Sizes(face, 0u, (FT_UInt)(size_px + 0.5f)); }
static int ft_font_load(FtFont *font, const char *path, float size_px) { FT_Face face = NULL; char *copy; if (!ensure_ft() || !path) return 0; if (g_ft.New_Face(g_ft_library, path, 0, &face) || !face) return 0; copy = dup_string(path); if (!copy) { g_ft.Done_Face(face); return 0; } ft_face_set_size(face, size_px); font->face = face; font->path = copy; return 1; }
static int ft_font_has_glyph(const FtFont *font, uint32_t ch) { return font && font->face && ensure_ft() && g_ft.Get_Char_Index((FT_Face)font->face, (FT_ULong)ch) != 0u; }
static float ft_font_glyph_advance(FtFont *font, uint32_t ch) { FT_GlyphSlotRec *slot; if (!font || !font->face || !ensure_ft()) return 0.0f; if (g_ft.Load_Char((FT_Face)font->face, (FT_ULong)ch, FT_LOAD_DEFAULT)) return 0.0f; slot = ((FT_Face)font->face)->glyph; return slot ? (float)slot->metrics.horiAdvance / FREETYPE_FIXED_POINT_SCALE : 0.0f; }
static void ft_font_line_metrics(FtFont *font, float *asc, float *desc, float *height) { FT_SizeRec *size; if (asc) *asc = 0.0f; if (desc) *desc = 0.0f; if (height) *height = 0.0f; if (!font || !font->face || !((FT_Face)font->face)->size) return; size = ((FT_Face)font->face)->size; if (asc) *asc = (float)size->metrics.ascender / FREETYPE_FIXED_POINT_SCALE; if (desc) *desc = (float)size->metrics.descender / FREETYPE_FIXED_POINT_SCALE; if (height) *height = (float)size->metrics.height / FREETYPE_FIXED_POINT_SCALE; }
