static unsigned ascii_cache_idx(unsigned char ch, int bold, int italic) { return (unsigned)(((bold != 0) * 2 + (italic != 0)) * ASCII_RANGE + (unsigned)(ch - 32u)); }
static uint32_t glyph_hash(uint32_t ch, uint8_t style) { uint32_t x = ch * 0x9e3779b1u; x ^= (uint32_t)style * 0x85ebca6bu; x ^= x >> 16; x *= 0x7feb352du; x ^= x >> 15; return x; }
