static int glyph_cache_reserve(rudo_font_atlas *atlas, size_t need) { GlyphCacheEntry *old_entries = atlas->cache, *new_entries; size_t old_cap = atlas->cache_cap, new_cap = atlas->cache_cap ? atlas->cache_cap : 256u, i; if (atlas->cache_cap >= need && atlas->cache_cap) return 1; while (new_cap < need * 2u) new_cap *= 2u; new_entries = (GlyphCacheEntry *)calloc(new_cap, sizeof(GlyphCacheEntry)); if (!new_entries) return 0; atlas->cache = new_entries; atlas->cache_cap = new_cap; atlas->cache_len = 0; for (i = 0; i < old_cap; ++i) if (old_entries[i].used) { size_t idx = (size_t)glyph_hash(old_entries[i].ch, old_entries[i].style) & (atlas->cache_cap - 1u); while (atlas->cache[idx].used) idx = (idx + 1u) & (atlas->cache_cap - 1u); atlas->cache[idx] = old_entries[i]; ++atlas->cache_len; } free(old_entries); return 1; }
static int glyph_cache_lookup(rudo_font_atlas *atlas, uint32_t ch, uint8_t style, rudo_glyph_info *out) { size_t idx; if (!atlas->cache_cap || !atlas->cache) return 0; idx = (size_t)glyph_hash(ch, style) & (atlas->cache_cap - 1u); for (;;) { GlyphCacheEntry *entry = &atlas->cache[idx]; if (!entry->used) return 0; if (entry->style == style && entry->ch == ch) { *out = entry->glyph; return 1; } idx = (idx + 1u) & (atlas->cache_cap - 1u); } }
static void glyph_cache_insert(rudo_font_atlas *atlas, uint32_t ch, uint8_t style, rudo_glyph_info glyph) { size_t idx; if ((atlas->cache_len + 1u) * 10u >= atlas->cache_cap * 7u) { if (!glyph_cache_reserve(atlas, atlas->cache_len + 1u)) return; } else if (!atlas->cache_cap) { if (!glyph_cache_reserve(atlas, 1u)) return; } idx = (size_t)glyph_hash(ch, style) & (atlas->cache_cap - 1u); while (atlas->cache[idx].used) { if (atlas->cache[idx].style == style && atlas->cache[idx].ch == ch) { atlas->cache[idx].glyph = glyph; return; } idx = (idx + 1u) & (atlas->cache_cap - 1u); } atlas->cache[idx].used = 1u; atlas->cache[idx].style = style; atlas->cache[idx].ch = ch; atlas->cache[idx].glyph = glyph; ++atlas->cache_len; }
static void reset_atlas(rudo_font_atlas *atlas) { memset(atlas->ascii_populated, 0, sizeof(atlas->ascii_populated)); glyph_cache_clear(atlas); atlas->current_x = atlas->current_y = atlas->row_height = 0u; memset(atlas->atlas_data, 0, (size_t)ATLAS_WIDTH * (size_t)ATLAS_HEIGHT); }
static int ensure_fallback_font_capacity(rudo_font_atlas *atlas, size_t need) { return grow_array((void **)&atlas->fallback_fonts, sizeof(FtFont), &atlas->fallback_font_cap, need); }
static void ensure_fallback_paths(rudo_font_atlas *atlas) { char **paths; size_t len, i; if (atlas->fallback_paths_resolved) return; atlas->fallback_paths_resolved = 1; paths = fontconfig_sort_files(atlas->request, &len); for (i = 0; i < len; ++i) { if (!paths[i]) continue; if (atlas->regular.path && !strcmp(paths[i], atlas->regular.path)) continue; append_unique_string(&atlas->fallback_paths, &atlas->fallback_path_len, &atlas->fallback_path_cap, paths[i]); } free_string_array(paths, len); }
static void ensure_bold_font(rudo_font_atlas *atlas) { static const char *const styles[] = { "style=Bold" }; char *path; if (atlas->bold_state != FONT_SLOT_UNRESOLVED) return; path = resolve_style_font_path(atlas->request, styles, RUDO_ARRAY_LEN(styles)); if (!path || (atlas->regular.path && !strcmp(path, atlas->regular.path)) || !ft_font_load(&atlas->bold, path, atlas->font_size)) { atlas->bold_state = FONT_SLOT_FAILED; free(path); return; } atlas->bold_state = FONT_SLOT_READY; free(path); }
static void ensure_italic_font(rudo_font_atlas *atlas) { static const char *const styles[] = { "style=Italic", "style=Oblique" }; char *path; if (atlas->italic_state != FONT_SLOT_UNRESOLVED) return; path = resolve_style_font_path(atlas->request, styles, RUDO_ARRAY_LEN(styles)); if (!path || (atlas->regular.path && !strcmp(path, atlas->regular.path)) || !ft_font_load(&atlas->italic, path, atlas->font_size)) { atlas->italic_state = FONT_SLOT_FAILED; free(path); return; } atlas->italic_state = FONT_SLOT_READY; free(path); }
static void ensure_bold_italic_font(rudo_font_atlas *atlas) { static const char *const styles[] = { "style=Bold Italic", "style=Bold Oblique", "style=Italic Bold" }; char *path; if (atlas->bold_italic_state != FONT_SLOT_UNRESOLVED) return; path = resolve_style_font_path(atlas->request, styles, RUDO_ARRAY_LEN(styles)); if (!path || (atlas->regular.path && !strcmp(path, atlas->regular.path)) || !ft_font_load(&atlas->bold_italic, path, atlas->font_size)) { atlas->bold_italic_state = FONT_SLOT_FAILED; free(path); return; } atlas->bold_italic_state = FONT_SLOT_READY; free(path); }
static FtFont *pick_styled_font(rudo_font_atlas *atlas, int bold, int italic) { if (bold && italic) { ensure_bold_italic_font(atlas); if (atlas->bold_italic_state == FONT_SLOT_READY) return &atlas->bold_italic; ensure_bold_font(atlas); if (atlas->bold_state == FONT_SLOT_READY) return &atlas->bold; ensure_italic_font(atlas); if (atlas->italic_state == FONT_SLOT_READY) return &atlas->italic; return &atlas->regular; } if (bold) { ensure_bold_font(atlas); return atlas->bold_state == FONT_SLOT_READY ? &atlas->bold : &atlas->regular; } if (italic) { ensure_italic_font(atlas); return atlas->italic_state == FONT_SLOT_READY ? &atlas->italic : &atlas->regular; } return &atlas->regular; }
static FtFont *pick_font_with_fallback(rudo_font_atlas *atlas, uint32_t ch, int bold, int italic) { FtFont *styled = pick_styled_font(atlas, bold, italic); size_t i; if (ch < 128u) return styled; if (ft_font_has_glyph(styled, ch)) return styled; if (ft_font_has_glyph(&atlas->regular, ch)) return &atlas->regular; for (i = 0; i < atlas->fallback_font_len; ++i) if (ft_font_has_glyph(&atlas->fallback_fonts[i], ch)) return &atlas->fallback_fonts[i]; ensure_fallback_paths(atlas); while (atlas->next_fallback_path < atlas->fallback_path_len) { FtFont font; const char *path = atlas->fallback_paths[atlas->next_fallback_path++]; ft_font_init(&font); if (!ft_font_load(&font, path, atlas->font_size)) continue; if (!ensure_fallback_font_capacity(atlas, atlas->fallback_font_len + 1u)) { ft_font_drop(&font); break; } atlas->fallback_fonts[atlas->fallback_font_len++] = font; if (ft_font_has_glyph(&atlas->fallback_fonts[atlas->fallback_font_len - 1u], ch)) return &atlas->fallback_fonts[atlas->fallback_font_len - 1u]; } return styled; }
static void copy_bitmap_rows(uint8_t *atlas_data, unsigned atlas_x, unsigned atlas_y, const FT_Bitmap *bitmap) { unsigned row; if (!bitmap || !bitmap->buffer || !bitmap->width || !bitmap->rows) return; for (row = 0; row < bitmap->rows; ++row) { const unsigned char *src = bitmap->pitch < 0 ? bitmap->buffer + (ptrdiff_t)row * (ptrdiff_t)bitmap->pitch : bitmap->buffer + (size_t)row * (size_t)bitmap->pitch; uint8_t *dst = atlas_data + ((size_t)(atlas_y + row) * (size_t)ATLAS_WIDTH + (size_t)atlas_x); memcpy(dst, src, bitmap->width); } }
static rudo_glyph_info rasterize_glyph(rudo_font_atlas *atlas, uint32_t ch, int bold, int italic) { FtFont *font; FT_GlyphSlotRec *slot; FT_Bitmap *bitmap; unsigned gw, gh, ax = 0, ay = 0; rudo_glyph_info info = empty_glyph_info(); font = pick_font_with_fallback(atlas, ch, bold, italic); if (!font || !font->face || !ensure_ft()) return info; if (g_ft.Load_Char((FT_Face)font->face, (FT_ULong)ch, FT_LOAD_RENDER)) return info; slot = ((FT_Face)font->face)->glyph; if (!slot) return info; bitmap = &slot->bitmap; gw = bitmap->width; gh = bitmap->rows; if (gw && gh) { if (atlas->current_x + gw > ATLAS_WIDTH) { atlas->current_y += atlas->row_height; atlas->current_x = atlas->row_height = 0u; } if (atlas->current_y + gh > ATLAS_HEIGHT) reset_atlas(atlas); if (atlas->current_x + gw > ATLAS_WIDTH) { atlas->current_y += atlas->row_height; atlas->current_x = atlas->row_height = 0u; } if (atlas->current_y + gh > ATLAS_HEIGHT) return info; ax = atlas->current_x; ay = atlas->current_y; copy_bitmap_rows(atlas->atlas_data, ax, ay, bitmap); atlas->current_x += gw + 1u; if (gh + 1u > atlas->row_height) atlas->row_height = gh + 1u; }
    info.u0 = (float)ax / (float)ATLAS_WIDTH; info.v0 = (float)ay / (float)ATLAS_HEIGHT; info.u1 = (float)(ax + gw) / (float)ATLAS_WIDTH; info.v1 = (float)(ay + gh) / (float)ATLAS_HEIGHT; info.width = (float)gw; info.height = (float)gh; info.offset_x = (float)slot->bitmap_left; info.offset_y = (float)(slot->bitmap_top - (int)gh); return info; }

rudo_font_atlas *rudo_font_atlas_new(float font_size, const char *preferred_family) { rudo_font_atlas *atlas; char *request, *regular_path; if (font_size < 1.0f) font_size = 1.0f; atlas = (rudo_font_atlas *)calloc(1u, sizeof(*atlas)); if (!atlas) return NULL; ft_font_init(&atlas->regular); ft_font_init(&atlas->bold); ft_font_init(&atlas->italic); ft_font_init(&atlas->bold_italic); request = trimmed_copy(preferred_family); if (!request) { free(atlas); return NULL; } regular_path = resolve_regular_font_path(request); if (!regular_path || !ft_font_load(&atlas->regular, regular_path, font_size)) { free(regular_path); free(request); free(atlas); fprintf(stderr, "[ERROR] No usable font found for '%s'\n", preferred_family ? preferred_family : RUDO_DEFAULT_FONT_FAMILY); return NULL; } atlas->atlas_data = (uint8_t *)calloc((size_t)ATLAS_WIDTH * (size_t)ATLAS_HEIGHT, 1u); if (!atlas->atlas_data) { free(regular_path); ft_font_drop(&atlas->regular); free(request); free(atlas); return NULL; } atlas->request = request; atlas->font_size = font_size; atlas->cell_width = compute_cell_width(&atlas->regular); atlas->cell_height = compute_cell_height(&atlas->regular); { float asc, desc, height; ft_font_line_metrics(&atlas->regular, &asc, &desc, &height); RUDO_UNUSED(desc); RUDO_UNUSED(height); atlas->baseline = asc > 0.0f ? asc : atlas->cell_height * FALLBACK_BASELINE_RATIO; } free(regular_path); return atlas; }
void rudo_font_atlas_free(rudo_font_atlas *atlas) { size_t i; if (!atlas) return; ft_font_drop(&atlas->regular); ft_font_drop(&atlas->bold); ft_font_drop(&atlas->italic); ft_font_drop(&atlas->bold_italic); for (i = 0; i < atlas->fallback_font_len; ++i) ft_font_drop(&atlas->fallback_fonts[i]); free(atlas->fallback_fonts); free_string_array(atlas->fallback_paths, atlas->fallback_path_len); free(atlas->atlas_data); free(atlas->cache); free(atlas->request); free(atlas); }
float rudo_font_atlas_cell_width(const rudo_font_atlas *atlas) { return atlas ? atlas->cell_width : 0.0f; }
float rudo_font_atlas_cell_height(const rudo_font_atlas *atlas) { return atlas ? atlas->cell_height : 0.0f; }
float rudo_font_atlas_baseline(const rudo_font_atlas *atlas) { return atlas ? atlas->baseline : 0.0f; }
rudo_glyph_info rudo_font_atlas_get_glyph(rudo_font_atlas *atlas, uint32_t ch, bool bold, bool italic) { rudo_glyph_info glyph; uint8_t style; if (!atlas) return empty_glyph_info(); if (ch >= 32u && ch <= 126u) { unsigned idx = ascii_cache_idx((unsigned char)ch, bold, italic); if (!atlas->ascii_populated[idx]) { atlas->ascii_cache[idx] = rasterize_glyph(atlas, ch, bold, italic); atlas->ascii_populated[idx] = 1u; } return atlas->ascii_cache[idx]; } style = (uint8_t)(((bold != 0) << 1) | (italic != 0)); if (glyph_cache_lookup(atlas, ch, style, &glyph)) return glyph; glyph = rasterize_glyph(atlas, ch, bold, italic); glyph_cache_insert(atlas, ch, style, glyph); return glyph; }
const uint8_t *rudo_font_atlas_data(const rudo_font_atlas *atlas, size_t *len_out) { if (len_out) *len_out = atlas ? (size_t)ATLAS_WIDTH * (size_t)ATLAS_HEIGHT : 0u; return atlas ? atlas->atlas_data : NULL; }
uint32_t rudo_font_atlas_width(const rudo_font_atlas *atlas) { RUDO_UNUSED(atlas); return ATLAS_WIDTH; }
uint32_t rudo_font_atlas_height(const rudo_font_atlas *atlas) { RUDO_UNUSED(atlas); return ATLAS_HEIGHT; }
